window.SmartRisk=window.SmartRisk||{};SmartRisk.Utils={formatDate(d=new Date()){return new Intl.DateTimeFormat("es-EC",{dateStyle:"long"}).format(d)},setTitle(t){document.title=`${t} | ${SmartRisk.Constants.APP_NAME}`},normalizeText(v){return String(v??"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().trim()},escapeHtml(v){return String(v).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;")},downloadCsv(filename,rows){if(!rows.length)return;const headers=Object.keys(rows[0]);const csv=[headers.join(","),...rows.map(r=>headers.map(h=>`"${String(r[h]??"").replaceAll('"','""')}"`).join(","))].join("\n");const blob=new Blob([csv],{type:"text/csv;charset=utf-8;"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=filename;a.click();URL.revokeObjectURL(url)}};